import{_ as o,c as t,o as n,a5 as a}from"./chunks/framework.CgT1UzWm.js";const u=JSON.parse('{"title":"Changelog v3.17.0","description":"NpgsqlRest v3.17.0: The headline of this release is MCP (Model Context Protocol) support — NpgsqlRest can project explicitly opted-in PostgreSQL routines as…","frontmatter":{"description":"NpgsqlRest v3.17.0: The headline of this release is MCP (Model Context Protocol) support — NpgsqlRest can project explicitly opted-in PostgreSQL routines as…","head":[["link",{"rel":"canonical","href":"https://npgsqlrest.github.io/guide/changelog/v3.17.0.html"}],["meta",{"property":"og:url","content":"https://npgsqlrest.github.io/guide/changelog/v3.17.0.html"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:title","content":"Changelog v3.17.0"}],["meta",{"property":"og:description","content":"NpgsqlRest v3.17.0: The headline of this release is MCP (Model Context Protocol) support — NpgsqlRest can project explicitly opted-in PostgreSQL routines as…"}],["meta",{"property":"og:image","content":"https://npgsqlrest.github.io/og-image.png"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Changelog v3.17.0"}],["meta",{"name":"twitter:description","content":"NpgsqlRest v3.17.0: The headline of this release is MCP (Model Context Protocol) support — NpgsqlRest can project explicitly opted-in PostgreSQL routines as…"}],["meta",{"name":"twitter:image","content":"https://npgsqlrest.github.io/og-image.png"}]]},"headers":[],"relativePath":"guide/changelog/v3.17.0.md","filePath":"guide/changelog/v3.17.0.md","lastUpdated":1782480183000}'),s={name:"guide/changelog/v3.17.0.md"};function i(r,e,c,d,l,p){return n(),t("div",null,e[0]||(e[0]=[a('<h1 id="changelog-v3-17-0" tabindex="-1">Changelog v3.17.0 <a class="header-anchor" href="#changelog-v3-17-0" aria-label="Permalink to &quot;Changelog v3.17.0&quot;">​</a></h1><h2 id="version-3-17-0-2026-06-13" tabindex="-1">Version <a href="https://github.com/NpgsqlRest/NpgsqlRest/tree/3.17.0" target="_blank" rel="noreferrer">3.17.0</a> (2026-06-13) <a class="header-anchor" href="#version-3-17-0-2026-06-13" aria-label="Permalink to &quot;Version [3.17.0](https://github.com/NpgsqlRest/NpgsqlRest/tree/3.17.0) (2026-06-13)&quot;">​</a></h2><p><a href="https://github.com/NpgsqlRest/NpgsqlRest/compare/3.16.3...3.17.0" target="_blank" rel="noreferrer">Full Changelog</a></p><p>The headline of this release is <strong>MCP (Model Context Protocol) support</strong> — NpgsqlRest can project explicitly opted-in PostgreSQL routines as MCP tools that an AI agent can discover and call. Supporting that, the release adds neutral plugin extension points, makes one breaking change to the OpenAPI C# API, and ships two configuration/runtime fixes.</p><div class="tip custom-block"><p class="custom-block-title">Walkthrough</p><p>For a hands-on tour — an &quot;Acme Store&quot; built from <code>.sql</code> files, a dual REST + MCP web page, and a real Claude agent driving the store — see the blog post <a href="/blog/mcp-server-postgresql-ai-tools-npgsqlrest.html">Turn PostgreSQL into MCP Tools an AI Agent Can Call</a>.</p></div><h2 id="new-features" tabindex="-1">New Features <a class="header-anchor" href="#new-features" aria-label="Permalink to &quot;New Features&quot;">​</a></h2><h3 id="mcp-model-context-protocol-server-—-new-npgsqlrest-mcp-plugin" tabindex="-1">MCP (Model Context Protocol) server — new <code>NpgsqlRest.Mcp</code> plugin <a class="header-anchor" href="#mcp-model-context-protocol-server-—-new-npgsqlrest-mcp-plugin" aria-label="Permalink to &quot;MCP (Model Context Protocol) server — new `NpgsqlRest.Mcp` plugin&quot;">​</a></h3><p>NpgsqlRest can now expose opted-in PostgreSQL routines as <strong>MCP tools</strong>, so an AI agent can discover them (<code>tools/list</code>) and execute them (<code>tools/call</code>) over the <a href="https://modelcontextprotocol.io/specification/2025-11-25" target="_blank" rel="noreferrer">Model Context Protocol</a> (spec <strong>2025-11-25</strong>). The entire MCP layer lives in the new plugin — <strong>core stays protocol-agnostic</strong>, built only on the neutral extension points below.</p><p><strong>Opt-in, never automatic.</strong> A routine becomes a tool only when its PostgreSQL comment carries the <code>mcp</code> annotation:</p><ul><li><p><code>mcp</code> — expose as a tool; description derived from the comment prose.</p></li><li><p><code>mcp &lt;text&gt;</code> — expose, with <code>&lt;text&gt;</code> as an inline (explicit) description.</p></li><li><p><code>mcp_description &lt;text&gt;</code> (alias <code>mcp_desc</code>) — explicit, authoritative description.</p></li><li><p><code>mcp_name &lt;name&gt;</code> — override the tool name (default: the routine name).</p></li><li><p><strong>A bare <code>mcp</code> with no HTTP tag is MCP-only</strong> — the tool exists with <strong>no</strong> public HTTP route. The HTTP tag controls the REST route and <code>mcp</code> controls the tool, independently: <code>HTTP GET</code> + <code>mcp</code> = both interfaces; <code>mcp</code> alone = tool only (an endpoint that exists solely because a plugin requested it defaults to internal-only, so opting into MCP never silently widens the HTTP surface); <code>internal</code> remains the explicit way to hide a declared HTTP route. Works identically for SQL file endpoints (a <code>.sql</code> file with <code>mcp</code> and no HTTP tag becomes an MCP-only tool; files with neither annotation are skipped as non-endpoint scripts, as before). All other annotations (<code>authorize</code>, parameter handling, …) apply unchanged.</p><p>Description precedence — the highest-priority source that is present wins, <strong>regardless of the order the lines appear</strong> in the comment; an explicit description <strong>suppresses</strong> the comment-prose fallback, so unrelated comment lines never leak in: <code>mcp_description</code> › inline <code>mcp &lt;text&gt;</code> › comment prose › routine name.</p></li></ul><p><strong>The endpoint.</strong> A single Streamable-HTTP JSON-RPC endpoint (default <code>/mcp</code>, POST only). It implements the lifecycle (<code>initialize</code> → protocol version + <code>tools</code> capability + <code>serverInfo</code>; <code>notifications/initialized</code> → <code>202</code>; <code>ping</code>), <code>tools/list</code> (with a JSON-Schema <code>inputSchema</code> per tool, derived from the routine&#39;s parameters), and <code>tools/call</code>. Transport rules per spec: the <code>Origin</code> header is validated (DNS-rebinding protection — a present, untrusted origin → <code>403</code>); a present <code>MCP-Protocol-Version</code> other than <code>2025-11-25</code> → <code>400</code>; <code>GET</code> → <code>405</code> (no SSE).</p><p><strong>Calling a tool.</strong> <code>tools/call</code> runs the routine through the same pipeline as the HTTP endpoint, forwarding the authenticated principal so <code>authorize</code> checks apply. Arguments map to the routine as a query string (GET/DELETE), a JSON body (POST/PUT), or path-segment substitution. The result carries:</p><ul><li><strong><code>structuredContent</code></strong> (always a JSON object): a single value → <code>{ &quot;value&quot;: … }</code>; a record/composite (or a set collapsed with <code>single</code>) → the object itself; a set → <code>{ &quot;items&quot;: [ … ] }</code>. The <code>text</code> content block carries the same JSON, serialized (backward-compatibility).</li><li><strong><code>outputSchema</code></strong> (declared on the tool) derived from the routine&#39;s return columns, nullable-aware so results always conform.</li><li>Two error channels: business failures → <code>isError: true</code> in the result; structural failures (unknown method/tool, malformed request) → JSON-RPC errors.</li></ul><p><strong>Authorization — OAuth 2.1 Resource Server</strong> (bring-your-own Authorization Server; token validation reuses the host&#39;s bearer authentication — NpgsqlRest is not an Authorization Server). Configured under <code>McpOptions:Authorization</code>:</p><ul><li><strong>Protected Resource Metadata (RFC 9728)</strong> served at <code>/.well-known/oauth-protected-resource{UrlPath}</code> when an Authorization Server is configured.</li><li><strong><code>RequireAuthorization</code></strong> gates the endpoint → <code>401</code> with <code>WWW-Authenticate: Bearer resource_metadata=&quot;…&quot;</code> (RFC 9728 §5.1) so the client can discover the AS; the PRM document itself stays anonymous.</li><li><strong>Audience binding (RFC 8707):</strong> with a canonical <code>Audience</code> configured, a token must carry it (<code>aud</code> claim) or it is rejected with <code>401</code>.</li><li><strong>Per-tool authorization:</strong> the routine&#39;s <code>authorize</code>/role check runs on <code>tools/call</code> → <code>401</code> if called anonymously, <code>403</code> <code>insufficient_scope</code> if the role is missing (RFC 6750 §3.1; challenges include <code>scope</code> and <code>resource_metadata</code>). No authorization logic is duplicated in the plugin — it reuses core&#39;s check.</li></ul><p><strong>Configuration</strong> — <code>NpgsqlRest:McpOptions</code>, disabled by default, surfaced in <code>--config</code>, <code>--config-schema</code>, and the JSON schema: <code>Enabled</code>, <code>UrlPath</code> (<code>/mcp</code>), <code>ServerName</code> (null → database name → <code>&quot;NpgsqlRest&quot;</code>), <code>ServerVersion</code> (<code>&quot;1.0.0&quot;</code>), <code>Instructions</code>, <code>ToolDescriptionSuffix</code>, <code>RateLimiterPolicy</code>, <code>AllowedOrigins</code>, and the <code>Authorization</code> object (<code>RequireAuthorization</code>, <code>AuthorizationServers</code>, <code>ScopesSupported</code>, <code>Audience</code>, <code>ProtectedResourceMetadataPath</code>, <code>FilterToolsByRole</code>).</p><p><strong>Diagnostics &amp; current limitations.</strong></p><ul><li>Enabling MCP does <strong>not</strong> enable authentication — it is configured separately (the host&#39;s <code>Auth</code> section). If <code>RequireAuthorization</code> is on but no authentication scheme is registered, a startup warning is logged.</li><li>A routine annotated <code>mcp</code> that also uses a feature with no MCP equivalent (<code>login</code>, <code>logout</code>, basic auth, <code>upload</code>, SSE) logs a build-time warning.</li><li>A routine&#39;s <code>rate_limiter</code> annotation does not carry to MCP (<code>tools/call</code> bypasses route middleware); pairing it with <code>mcp</code> logs a build-time warning. Use <code>McpOptions:RateLimiterPolicy</code> (a host-registered ASP.NET rate-limiter policy) to throttle the whole <code>/mcp</code> endpoint.</li><li><code>tools/list</code> lists every opted-in tool by default (keeping them discoverable); set <code>Authorization.FilterToolsByRole</code> to hide tools the caller can&#39;t run. Authorization is enforced on <code>tools/call</code> regardless.</li><li>The JSON-RPC layer is hand-rolled over <code>System.Text.Json.Nodes</code> with relaxed escaping (conventional <code>application/json</code> output) — no reflection-based serialization, AOT-safe (verified via <code>dotnet publish -p:PublishAot=true</code>).</li></ul><h3 id="plugin-extension-points-on-routineendpoint" tabindex="-1">Plugin extension points on <code>RoutineEndpoint</code> <a class="header-anchor" href="#plugin-extension-points-on-routineendpoint" aria-label="Permalink to &quot;Plugin extension points on `RoutineEndpoint`&quot;">​</a></h3><p>Neutral, plugin-facing hooks were added so a plugin can own its comment annotations without leaking plugin concepts into core (both MCP and the OpenAPI plugin are now built on these):</p><ul><li><strong><code>IEndpointCreateHandler.HandleCommentLine(...)</code></strong> (new default-interface method) — core offers each unrecognized comment line to handlers within its single parse pass; a handler claims it by returning a <code>CommentLineResult</code> (a log label + <code>RequestsEndpoint</code>). Tokens are pre-split by core. Non-breaking.</li><li><strong><code>RoutineEndpoint.Items</code></strong> (lazy <code>IDictionary&lt;string, object?&gt;</code>) + <strong><code>TryGetItem</code></strong> — a per-endpoint property bag for plugin metadata (the <code>HttpContext.Items</code> pattern), namespaced by key.</li><li><strong><code>RoutineEndpoint.UnhandledCommentLines</code></strong> (<code>string[]?</code>) — comment prose that neither core nor any handler claimed.</li><li><strong><code>CommentsMode.OnlyAnnotated</code></strong> (new) — creates an endpoint when the comment has an HTTP tag <strong>or</strong> a plugin requests one. An endpoint created <strong>solely</strong> by a plugin request (no HTTP tag) defaults to <strong>internal-only</strong> — the plugin asked for a projection (an MCP tool), not a route — so a bare <code>mcp</code> is MCP-only (a debug log notes the defaulting). The <strong>client now defaults to <code>OnlyAnnotated</code></strong>; existing <code>OnlyWithHttpTag</code> configs are unaffected — it is kept as an identical-behavior alias.</li><li><strong><code>IEndpointCreateHandler.EndpointRequestingAnnotations</code></strong> (new default-interface property, default empty) — the annotation keywords for which the handler requests endpoints (Mcp: <code>mcp</code>, <code>mcp_name</code>, <code>mcp_description</code>, <code>mcp_desc</code>). Lets sources with a cheap textual pre-gate recognize endpoint candidates: the SQL file source passes a file whose comment carries an HTTP tag <strong>or</strong> one of these keywords, so a bare-<code>mcp</code> <code>.sql</code> file becomes an MCP-only tool while scripts with neither are still skipped without ever being described.</li></ul><h3 id="name-annotation-substitution-can-resolve-allowlisted-environment-variables" tabindex="-1"><code>{name}</code> annotation substitution can resolve allowlisted environment variables <a class="header-anchor" href="#name-annotation-substitution-can-resolve-allowlisted-environment-variables" aria-label="Permalink to &quot;`{name}` annotation substitution can resolve allowlisted environment variables&quot;">​</a></h3><p>The <code>{name}</code> placeholders in annotation values (response headers, custom parameters, HTTP custom type URL/headers/body) could only resolve <strong>request parameters</strong>. They can now also resolve <strong>allowlisted environment variables</strong>, so e.g. an outbound API key or a per-pod server name doesn&#39;t have to be routed through a request parameter:</p><details class="code-collapsible" open><summary>sql</summary><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">comment on type weather_api is </span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&#39;GET https://api.example.com/v1/current?city={_city}</span></span>\n<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">Authorization: Bearer {WEATHER_API_KEY}&#39;</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div></details><ul><li><strong>Opt-in allowlist</strong> <code>NpgsqlRest:AvailableEnvVars</code> (mirrors <code>StaticFiles:ParseContentOptions:AvailableEnvVars</code>): array of names, or an object of <code>name → default</code>. Only listed names are ever read from the environment — the allowlist is the security boundary. (C# API: <code>NpgsqlRestOptions.SubstitutionEnvironmentVariables</code>, a resolved <code>name → value</code> dictionary.)</li><li>Resolved <strong>once at startup</strong>, matched <strong>case-insensitively</strong>, injected as the <strong>raw</strong> value. A <strong>routine parameter of the same name takes precedence</strong>.</li><li><strong>Security:</strong> a value substituted into a <em>response</em> header is sent to the client — reserve secrets for outbound HTTP-type calls / custom parameters, and use response headers only for non-secret values (e.g. server/environment name).</li></ul><h3 id="tsclient-exporttypes-—-emit-request-response-interfaces-with-the-export-keyword" tabindex="-1">TsClient: <code>ExportTypes</code> — emit request/response interfaces with the <code>export</code> keyword <a class="header-anchor" href="#tsclient-exporttypes-—-emit-request-response-interfaces-with-the-export-keyword" aria-label="Permalink to &quot;TsClient: `ExportTypes` — emit request/response interfaces with the `export` keyword&quot;">​</a></h3><p>The TypeScript client generator (<code>NpgsqlRest.TsClient</code>) previously emitted its request/response (and composite) interfaces as plain <code>interface</code> declarations: module-private when inlined into the client file (<code>CreateSeparateTypeFile: false</code>), or ambient/global in the separate <code>{name}Types.d.ts</code> file (the default). Neither form could be imported by other modules. The new <strong><code>ExportTypes</code></strong> option (config <code>NpgsqlRest:ClientCodeGen:ExportTypes</code>, default <code>false</code>) emits them as <code>export interface</code> so they can be imported:</p><ul><li><strong>Inline</strong> (<code>CreateSeparateTypeFile: false</code>) — interfaces are emitted as <code>export interface</code> in the same file as the functions.</li><li><strong>Separate file</strong> (<code>CreateSeparateTypeFile: true</code>) — the type file becomes an importable module <strong><code>{name}Types.ts</code></strong> (<code>export interface …</code>) instead of an ambient <strong><code>{name}Types.d.ts</code></strong>, and the generated client file gets an <code>import type { … } from &quot;./{name}Types&quot;;</code> referencing the named types.</li></ul><p>Has no effect when <code>SkipTypes</code> is <code>true</code>. Defaulting to <code>false</code> keeps existing output byte-for-byte unchanged.</p><h2 id="breaking-changes" tabindex="-1">Breaking Changes <a class="header-anchor" href="#breaking-changes" aria-label="Permalink to &quot;Breaking Changes&quot;">​</a></h2><h3 id="⚠️-safer-configuration-defaults-cors-credentials-passkey-requirements-connection-testing" tabindex="-1">⚠️ Safer configuration defaults: CORS credentials, passkey requirements, connection testing <a class="header-anchor" href="#⚠️-safer-configuration-defaults-cors-credentials-passkey-requirements-connection-testing" aria-label="Permalink to &quot;⚠️ Safer configuration defaults: CORS credentials, passkey requirements, connection testing&quot;">​</a></h3><p>Three configuration defaults changed as part of a security/consistency audit of the shipped <code>appsettings.json</code> against the in-code defaults. <strong>You are affected only if your custom configuration omits these keys</strong> — set them explicitly to keep the old behavior.</p><ul><li><strong><code>Cors:AllowCredentials</code> now defaults to <code>false</code></strong> (was <code>true</code>). Credentials (cookies, authorization headers) in cross-origin requests must now be enabled deliberately, and only together with an explicit <code>AllowedOrigins</code> list. This only matters when <code>Cors:Enabled</code> is <code>true</code>.</li><li><strong><code>Auth:PasskeyAuth:UserVerificationRequirement</code> and <code>ResidentKeyRequirement</code> code defaults are now <code>&quot;required&quot;</code></strong> (were <code>&quot;preferred&quot;</code>). The shipped <code>appsettings.json</code> already said <code>&quot;required&quot;</code> — the in-code fallback and <code>--config</code> defaults disagreed; they now match the stronger, documented posture.</li><li><strong><code>ConnectionSettings:TestConnectionStrings</code> code default is now <code>true</code></strong> (was <code>false</code>). Same class of fix: the shipped <code>appsettings.json</code> already said <code>true</code>; the in-code default now agrees, so connection strings are tested at startup even when the key is omitted.</li></ul><h3 id="⚠️-openapi-annotation-handling-moved-out-of-core-c-api-only" tabindex="-1">⚠️ OpenAPI annotation handling moved out of core (C# API only) <a class="header-anchor" href="#⚠️-openapi-annotation-handling-moved-out-of-core-c-api-only" aria-label="Permalink to &quot;⚠️ OpenAPI annotation handling moved out of core (C# API only)&quot;">​</a></h3><p>The public properties <strong><code>RoutineEndpoint.OpenApiHide</code> and <code>RoutineEndpoint.OpenApiTags</code> were removed</strong>, along with the core <code>openapi</code> comment-annotation handler. The OpenAPI plugin now parses <code>openapi hide</code> / <code>hidden</code> / <code>ignore</code> / <code>tag &lt;…&gt;</code> itself (from <code>UnhandledCommentLines</code>).</p><ul><li><strong>No change for annotation users</strong> — the <code>openapi …</code> comment annotations behave exactly as before (and, as before, only take effect when the OpenAPI plugin is loaded).</li><li><strong>Affected only if</strong> your code sets <code>endpoint.OpenApiHide</code> / <code>endpoint.OpenApiTags</code> directly (e.g. in an <code>EndpointCreated</code> callback) — use the <code>openapi</code> comment annotation instead.</li></ul><h2 id="fixes" tabindex="-1">Fixes <a class="header-anchor" href="#fixes" aria-label="Permalink to &quot;Fixes&quot;">​</a></h2><h3 id="internal-only-endpoints-are-excluded-from-generated-client-artifacts-and-api-docs" tabindex="-1">Internal-only endpoints are excluded from generated client artifacts and API docs <a class="header-anchor" href="#internal-only-endpoints-are-excluded-from-generated-client-artifacts-and-api-docs" aria-label="Permalink to &quot;Internal-only endpoints are excluded from generated client artifacts and API docs&quot;">​</a></h3><p>Endpoints marked <code>internal</code> (no public HTTP route — proxy/HTTP-type-callable, or now a bare-<code>mcp</code> MCP-only routine) were still emitted into the generated TypeScript client (a <code>fetch</code> wrapper), the generated <code>.http</code> file (a request line), and the generated <strong>OpenAPI document</strong> (a path entry). All target a route that returns <code>404</code>, so the generated artifacts advertised endpoints that don&#39;t exist. The <code>TsClient</code>, <code>HttpFiles</code>, and <code>OpenApi</code> plugins now skip <code>InternalOnly</code> endpoints. (Surfaced by the new MCP-only mode, where a bare <code>@mcp</code> routine has no HTTP route.)</p><h3 id="🔴-security-sse-scope-hints-were-not-enforced-—-hint-scoped-events-were-delivered-to-every-subscriber" tabindex="-1">🔴 Security: SSE scope hints were not enforced — hint-scoped events were delivered to every subscriber <a class="header-anchor" href="#🔴-security-sse-scope-hints-were-not-enforced-—-hint-scoped-events-were-delivered-to-every-subscriber" aria-label="Permalink to &quot;🔴 Security: SSE scope hints were not enforced — hint-scoped events were delivered to every subscriber&quot;">​</a></h3><p>Events published with a per-event scope override — <code>RAISE INFO ... USING HINT = &#39;authorize&#39;</code> or <code>USING HINT = &#39;authorize &lt;role-or-user&gt; ...&#39;</code> — were delivered to <strong>all</strong> connected SSE subscribers, including subscribers without the named role <strong>and unauthenticated subscribers</strong>. The hint was parsed correctly, but a control-flow bug (<code>else if</code> chaining) skipped the authorization checks whenever a hint was present. Endpoint-level scoping via the <code>sse_scope</code> annotation (no hint) was NOT affected.</p><p><strong>Impact:</strong> any deployment using the documented per-user/per-role <code>USING HINT</code> pattern (e.g. private user messages or role-targeted notifications over SSE) was broadcasting those events to every connected subscriber. <strong>Upgrade is strongly recommended</strong> for anyone using SSE with hint-based scoping.</p><p>Fixed by decoupling scope enforcement from hint parsing so the <code>Matching</code>/<code>Authorize</code> checks always run on the effective scope. Covered by new tests proving delivery-by-ordering: a role-scoped event reaches only matching subscribers, a bare <code>authorize</code> event reaches only authenticated subscribers, and anonymous subscribers receive neither.</p><h3 id="malformed-json-request-body-now-returns-400-bad-request-was-404-not-found" tabindex="-1">Malformed JSON request body now returns <code>400 Bad Request</code> (was <code>404 Not Found</code>) <a class="header-anchor" href="#malformed-json-request-body-now-returns-400-bad-request-was-404-not-found" aria-label="Permalink to &quot;Malformed JSON request body now returns `400 Bad Request` (was `404 Not Found`)&quot;">​</a></h3><p>When an endpoint expects a JSON body and the request body is present but not a parseable JSON <strong>object</strong> (truncated JSON, a bare array/string, …), the response is now <strong><code>400 Bad Request</code></strong>. Previously the failed parse fell through to parameter matching and surfaced as a misleading <code>404 Not Found</code>. Parse failures were and still are logged; valid requests and empty-body handling are unchanged.</p><h3 id="passkey-webauthn-diagnostics-cbor-decode-failures-are-no-longer-silent" tabindex="-1">Passkey/WebAuthn diagnostics: CBOR decode failures are no longer silent <a class="header-anchor" href="#passkey-webauthn-diagnostics-cbor-decode-failures-are-no-longer-silent" aria-label="Permalink to &quot;Passkey/WebAuthn diagnostics: CBOR decode failures are no longer silent&quot;">​</a></h3><ul><li>A malformed WebAuthn attestation object now logs a <strong>Warning</strong> naming the decode failure (exception + payload length — never the payload itself) instead of failing silently into a generic <code>attestation_invalid</code> error. This gives operators an audit trail for both debugging and attack detection.</li><li><strong>Indefinite-length CBOR arrays</strong> (legal in the lax conformance mode the decoder uses) are now decoded correctly; previously they failed the whole attestation.</li><li>A <strong>startup warning</strong> is logged when Passkey authentication is enabled with an empty <code>RelyingPartyOrigins</code> list — in that state WebAuthn origin validation accepts <em>any</em> origin, which is not recommended for production.</li></ul><h3 id="name-parameter-value-placeholders-case-insensitive-matching-typo-warning" tabindex="-1"><code>{name}</code> parameter-value placeholders: case-insensitive matching + typo warning <a class="header-anchor" href="#name-parameter-value-placeholders-case-insensitive-matching-typo-warning" aria-label="Permalink to &quot;`{name}` parameter-value placeholders: case-insensitive matching + typo warning&quot;">​</a></h3><p>The <code>{name}</code> placeholders that inject a request&#39;s parameter values into annotation values (response headers incl. <code>Content-Type</code>, custom parameters such as upload paths, and HTTP custom type URL/headers/body) had two rough edges:</p><ul><li><strong>Case sensitivity was inconsistent.</strong> Substitution matched names case-sensitively, while the related resolved-parameter SQL expression resolver matched case-insensitively. Substitution is now <strong>case-insensitive</strong> too (<code>{userId}</code>, <code>{USERID}</code>, <code>{userid}</code> all resolve the same parameter), consistent with PostgreSQL identifier folding.</li><li><strong>Typos were silent.</strong> An unknown placeholder is left as literal text at request time (unchanged), but a misspelling like <code>{_fil}</code> for <code>{_file}</code> shipped silently into a header/path. NpgsqlRest now logs a <strong>build-time warning</strong> naming the unknown placeholder. The check covers response headers and custom parameters and only flags identifier-shaped tokens, so <code>{0}</code> and JSON-like <code>{&quot;a&quot;:1}</code> are never mistaken for placeholders.</li></ul><h3 id="bare-cached-no-parameter-list-used-only-the-routine-name-as-the-cache-key" tabindex="-1">Bare <code>@cached</code> (no parameter list) used only the routine name as the cache key <a class="header-anchor" href="#bare-cached-no-parameter-list-used-only-the-routine-name-as-the-cache-key" aria-label="Permalink to &quot;Bare `@cached` (no parameter list) used only the routine name as the cache key&quot;">​</a></h3><p><code>@cached</code> without an explicit parameter list is documented to key on <strong>all</strong> routine parameters, but the implementation left the cache-key parameter set empty — so the key was just the routine identifier, and <strong>every call returned the first response cached for that routine regardless of inputs</strong> until the TTL expired (a search/filter endpoint would serve the first query&#39;s results to every subsequent query). Endpoints that listed parameters explicitly (<code>@cached p1, p2</code>) were unaffected. All cache backends (<code>Memory</code>, <code>Redis</code>, <code>Hybrid</code>) were affected. Fixed by treating &quot;no list&quot; as &quot;every parameter&quot; at annotation-parse time.</p><h3 id="hybridcache-cache-key-contains-invalid-content-on-nullable-cached-params" tabindex="-1">HybridCache <code>Cache key contains invalid content</code> on nullable cached params <a class="header-anchor" href="#hybridcache-cache-key-contains-invalid-content-on-nullable-cached-params" aria-label="Permalink to &quot;HybridCache `Cache key contains invalid content` on nullable cached params&quot;">​</a></h3><p>When <code>CacheOptions.Type</code> was <code>Hybrid</code> and a cached routine had a nullable parameter, every call where that parameter was null logged <code>Microsoft.Extensions.Caching.Hybrid: Cache key contains invalid content</code> and silently bypassed the cache — the endpoint still ran against the DB and returned correct data, but lost the cache hit and stampede protection for that key. Root cause: NpgsqlRest&#39;s internal cache-key encoding used a null byte (<code>\\x00</code>) in its null marker, which HybridCache rejects.</p><p><code>HybridCacheWrapper</code> now hashes every key into a SHA-256 hex string before passing it to HybridCache, so keys are valid regardless of source content; the null marker source-side also no longer uses <code>\\x00</code> (it is delimited by the existing <code>\\x1F</code> separator), which is friendlier to Redis keys and log collectors across all backends. The <code>UseHashedCacheKeys</code> / <code>HashKeyThreshold</code> options keep their original purpose (Redis-backend key length / memory) and are simply a no-op for the Hybrid backend now. <strong>No user action required</strong> — Hybrid in-memory entries are flushed on restart.</p><h3 id="json-command-parameters-accept-json-jsonb-or-text" tabindex="-1">JSON command parameters accept <code>json</code>, <code>jsonb</code>, or <code>text</code> <a class="header-anchor" href="#json-command-parameters-accept-json-jsonb-or-text" aria-label="Permalink to &quot;JSON command parameters accept `json`, `jsonb`, or `text`&quot;">​</a></h3><p>JSON payloads passed to user-authored SQL commands were bound with a hardcoded <code>json</code> type, so a function declaring the receiving parameter as <code>jsonb</code> or <code>text</code> failed at runtime with PostgreSQL <code>42883</code> <em>&quot;function does not exist&quot;</em> — even though the documentation states all three are acceptable.</p><p>The binding now uses an untyped (<code>unknown</code>) parameter, which PostgreSQL resolves server-side via the target type&#39;s input function. Affected commands: external-auth <code>Auth.External.LoginCommand</code> (<code>$4</code> provider data, <code>$5</code> analytics), CSV/Excel upload row commands (per-row metadata, Excel JSON data), and the Passkey/Fido2 commands. <strong>Fully backward compatible</strong> — <code>json</code>-typed parameters are unchanged; <code>jsonb</code> and <code>text</code> now also work, and <code>NULL</code> / quoted / array values round-trip correctly.</p><h3 id="optional-name-and-required-name-environment-variable-placeholders" tabindex="-1">Optional <code>{NAME}</code> and required <code>{!NAME}</code> environment-variable placeholders <a class="header-anchor" href="#optional-name-and-required-name-environment-variable-placeholders" aria-label="Permalink to &quot;Optional `{NAME}` and required `{!NAME}` environment-variable placeholders&quot;">​</a></h3><p>With <code>Config:ParseEnvironmentVariables</code> enabled (the default), config values support two placeholder forms, for <strong>every</strong> value type (bool, int, string, enum, arrays, dictionaries):</p><ul><li><strong><code>{NAME}</code> — optional.</strong> Substituted with the variable&#39;s value when set; left untouched when not — so typed <code>bool</code>/<code>int</code> reads fall back to their default instead of crashing, and legitimate non-env brace syntax (e.g. a Serilog <code>OutputTemplate</code>) is preserved.</li><li><strong><code>{!NAME}</code> — required.</strong> Substituted with the value, or <strong>throws a clear startup error</strong> naming the variable when it is not set.</li></ul><p>This fixes a startup crash: previously a missing optional variable left an unresolved <code>{NAME}</code> token that a typed read (e.g. <code>GetConfigBool</code>) rejected. Genuinely invalid <em>values</em> (e.g. <code>&quot;maybe&quot;</code> for a bool) still throw.</p><details class="code-collapsible" open><summary>jsonc</summary><div class="language-jsonc vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">jsonc</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&quot;Enabled&quot;</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">: </span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&quot;{GITHUB_AUTH_ENABLED}&quot;</span><span style="--shiki-light:#9CA0B0;--shiki-light-font-style:italic;--shiki-dark:#6C7086;--shiki-dark-font-style:italic;">   // env unset → feature defaults to off (no crash)</span></span>\n<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&quot;Enabled&quot;</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">: </span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&quot;{!GITHUB_AUTH_ENABLED}&quot;</span><span style="--shiki-light:#9CA0B0;--shiki-light-font-style:italic;--shiki-dark:#6C7086;--shiki-dark-font-style:italic;">  // env unset → startup error naming the variable</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div></details><h2 id="tests" tabindex="-1">Tests <a class="header-anchor" href="#tests" aria-label="Permalink to &quot;Tests&quot;">​</a></h2><ul><li>An MCP test suite covering the lifecycle, <code>tools/list</code> / <code>tools/call</code>, <code>structuredContent</code> and <code>outputSchema</code> across return shapes (scalar, record, set, array, custom composite), parameter mapping (query / body / path; typed, optional, null, and json arguments), authorization (PRM, 401/403, audience binding), transport rules, and protocol edge cases.</li><li>A binding-contract test locking the PostgreSQL/Npgsql resolution the JSON-parameter fix relies on (<code>json</code>-only for the old binding; <code>json</code>/<code>jsonb</code>/<code>text</code> for the new one, including <code>NULL</code> and round-trip integrity), plus end-to-end CSV upload tests for a row-command metadata parameter declared as <code>json</code>, <code>jsonb</code>, and <code>text</code>.</li><li>Config tests for optional <code>{NAME}</code> (resolves when set; left untouched / defaults when not — including Serilog-template preservation) and required <code>{!NAME}</code> (throws when unset) across <code>GetConfigBool</code> / <code>GetConfigInt</code> / <code>GetConfigStr</code> and the <code>ResolveEnv</code> resolver.</li><li>Malformed-JSON body tests: truncated JSON and non-object JSON → <code>400</code>; valid body unchanged.</li><li>SSE hardening suite: hint-scope authorization (the security-fix regression test — role-scoped, authenticated-scoped, and unscoped delivery across three differently-authenticated subscribers), multi-subscriber exactly-once fan-out, per-stream publish ordering, and subscriber-disconnect resilience.</li><li>Cache concurrency races: TTL-expiry under concurrent bursts (exactly one execution per cache window) and concurrent invalidation + read storms (no errors, cache coherent after).</li><li>CRUD endpoint authorization parity: table-comment <code>authorize</code>/roles enforced across select/insert/update/delete variants (401 anonymous, 403 wrong role, full cycle with the right role).</li></ul>',65)]))}const g=o(s,[["render",i]]);export{u as __pageData,g as default};
